/// <summary>
///    The <c>ETG_InterCompanyGoodsInTransitController</c> class is used for associated reports.
/// </summary>
/// <remarks>
///    This class contains methods which support the <c>InterCompanyGoodsInTransit</c> reports when it is
///    invoked from the <c>InterCompanyGoodsInTransit</c> menu item.
/// </remarks>
public class ETG_InterCompanyGoodsInTransitController extends SrsReportRunController
{
}

Method.Source:
public static ETG_InterCompanyGoodsInTransitController construct()
{
    return new ETG_InterCompanyGoodsInTransitController();
}

/// <summary>
/// description for the intercomapny.
/// </summary>
/// <returns></returns>
public static ClassDescription description()
{
    return "@SYS332445";
}

/// <summary>
///    Provides an entry point for the <c>InterCompanyGoodsInTransit</c> class.
/// </summary>
/// <param name="_args">
///    The arguments for the class.
/// </param>
public static void main(Args _args)
{
    ETG_InterCompanyGoodsInTransitController    interCompanyGoodsInTransitController;

    interCompanyGoodsInTransitController = ETG_InterCompanyGoodsInTransitController::newFromArgs(_args);
    interCompanyGoodsInTransitController.startOperation();
}

/// <summary>
///    Retrieves a new instance of the <c>InterCompanyGoodsInTransit</c> class.
/// </summary>
/// <param name="_args">
///    The arguments that are used to initialize the class.
/// </param>
/// <returns>
///    A new instance of the <c>InterCompanyGoodsInTransit</c> class.
/// </returns>
public static ETG_InterCompanyGoodsInTransitController newFromArgs(Args _args)
{
    ETG_InterCompanyGoodsInTransitController    interCompanyGoodsInTransitController;

    if (!_args)
    {
        throw error(strFmt("@SYS22828", funcName()));
    }

    interCompanyGoodsInTransitController = ETG_InterCompanyGoodsInTransitController::construct();

    switch (_args.parmEnum())
    {
        case InterCompanyGoodsInTransitLayout::Transactions:
            interCompanyGoodsInTransitController.parmReportName(ssrsReportStr(ETG_InterCompanyGoodsInTransitTransactionsSSRS, Report));
            break;
        case InterCompanyGoodsInTransitLayout::Totals:
            interCompanyGoodsInTransitController.parmReportName(ssrsReportStr(ETG_InterCompanyGoodsInTransitTransactionsSSRS, Report));
            break;
    }

    interCompanyGoodsInTransitController.parmArgs(_args);

    return interCompanyGoodsInTransitController;
}

protected void prePromptModifyContract()
{
    InterCompanyGoodsInTransitContract  contract;
    contract    =   this.parmReportContract().parmRdpContract() ;
    contract.parmViewConfigId(NoYes::Yes);
    contract.parmViewInventColorId(NoYes::Yes);
    contract.parmViewInventSizeId(NoYes::Yes);
    contract.parmViewInventStyleId(NoYes::Yes);

    super();
}
